		c := s[j]
		if c == '\n' {
			return 0, InterpolatedPart{}, fmt.Errorf("interpolation slot must be on one line")
		}
		if inStr {
			if c == '\\' {
				j += 2
				continue
			}
			if c == '\'' {
				inStr = false
			}
			j++
			continue
		}
